import { organizationService } from '../../services/organizationService';
import { db } from '../../firebaseConfig';
import { runTransaction } from 'firebase/firestore';

// Mock Firestore
jest.mock('../../firebaseConfig', () => ({
    db: {},
}));

jest.mock('firebase/firestore', () => ({
    doc: jest.fn((db, collection, id) => ({ id: id || 'mock-doc-id' })),
    collection: jest.fn(),
    setDoc: jest.fn(),
    updateDoc: jest.fn(),
    runTransaction: jest.fn(),
    arrayUnion: jest.fn((val) => [val]),
}));

describe('Organization Creation Integration', () => {
    beforeEach(() => {
        jest.clearAllMocks();
    });

    it('should successfully create an organization and sync to user profile', async () => {
        // Setup mock transaction
        const mockTransaction = {
            set: jest.fn(),
            update: jest.fn(),
        };
        (runTransaction as jest.Mock).mockImplementation(async (db, callback) => {
            await callback(mockTransaction);
        });

        // Execute function
        const userId = 'user-123';
        const orgName = 'Test Squad';
        const result = await organizationService.createOrganizationFromOnboarding(orgName, userId);

        // Verify result
        expect(result.id).toContain('test-squad-');
        expect(result.name).toBe(orgName);
        expect(result.ownerId).toBe(userId);
        expect(result.inviteCode).toBeDefined();
        expect(result.inviteCode.length).toBe(6);

        // Verify transaction interactions
        expect(runTransaction).toHaveBeenCalled();
        expect(mockTransaction.set).toHaveBeenCalledTimes(1); // the org doc
        expect(mockTransaction.update).toHaveBeenCalledTimes(1); // the user doc

        // Verify the organization was created with correct initial state
        const setCallArgs = mockTransaction.set.mock.calls[0];
        expect(setCallArgs[1]).toEqual(expect.objectContaining({
            name: orgName,
            ownerId: userId,
            settings: expect.objectContaining({
                requireApproval: true,
                requirePayment: false
            }),
            members: [userId],
            admins: [userId]
        }));

        // Verify the user profile was synced correctly
        const updateCallArgs = mockTransaction.update.mock.calls[0];
        expect(updateCallArgs[1]).toEqual(expect.objectContaining({
            isApproved: true,
            isAdmin: true,
            activeOrgId: result.id,
            orgIds: [result.id]
        }));
    });
});
